(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,40664,e=>{"use strict";let a={EN:{nav:{home:"Home",about:"About",features:"Features",pythia:"Pythia AI",price:"Price",faq:"FAQ",blog:"Blog",getStarted:"Get Started",howItWorks:"How It Works",equipment:"Equipment",product:"Product",resources:"Resources",softwareTpv:"Supermarket POS Software",comparativas:"Compare",contact:"Contact",impresoraTickets:"Receipt Printer",verifactu:"VeriFactu"},hero:{badge:"New: AI-Powered Demand Prediction 🚀",titleLine1:"Supermarket Software",titleLine2:"with Verifactu.",description1:"Salut is the ultimate supermarket POS software. Bring your entire operation together, from cash register software to stock and staff management.",description2:" Implemented in a single day.",btnStart:"Get Started",btnEquipment:"View our Equipment",compatibleWith:"Compatible with",verifactu:"Verifactu",playVideo:"Play video"},solution:{badge:"The Solution",title:"The Best Supermarket Management Software",description:"Salut! is a supermarket ERP software that combines everything you need into one easy-to-use platform. Your POS, inventory, and analytics software without spreadsheets.",pos:"POS",inventory:"Inventory",purchasing:"Purchasing",analytics:"Analytics",staff:"Staff"},problem:{badge:"ABOUT",title:"Boosting supermarket sales with smart technologies",description:"Salut! provides independent supermarket software with the tools of large chains, helping to reduce stockouts through fast and modern POS software.",btnDemo:"Get Started",f1:{title:"Reduce Out-of-Stock",desc:"AI-powered demand forecasting and automated replenishment keep shelves full and customers coming back. Capture more sales and never miss demand."},f2:{title:"Minimize Waste & Protect Margins",desc:"Track expiration dates, optimize inventory turnover, and reduce shrink to improve profitability."},f3:{title:"Increase Operational Efficiency",desc:"Automate purchasing, inventory, and reporting to save time, reduce errors, and empower your team."},f4:{title:"One Unified System",desc:"POS, inventory, accounting, and analytics in a single platform. Less complexity. More visibility. Full control."}},features:{title:"The All-in-One Solution",description:"Salut! combines everything you need to run your supermarket into one easy-to-use platform. No more spreadsheets, no more disconnected systems,\nno more manual operations.",f1:{title:"AI Demand Intelligence",desc:"Predict demand with precision using adaptive machine learning models trained on your sales history.",highlight:">90% Accuracy"},f2:{title:"Smart Supplier Automation",desc:"Automatically generate purchase orders based on real-time sales velocity.",highlight:"Save 12h/week"},f3:{title:"Live Inventory Control",desc:"Monitor stock levels with predictive low-stock alerts and replenishment triggers.",highlight:"Zero Stockouts"},f4:{title:"Business Intelligence",desc:"Turn operational data into active insights with real-time dashboards and reports.",highlight:"Instant P&L"}},steps:{badge:"SPEED",title:"One day to transformation",description:"We don't believe in long implementations. You're up and running tomorrow,\nnot next month.",btnStart:"Get started",s1:{title:"Today",desc:"Book a demo and see how Salut works tailored to your store's needs."},s2:{title:"Day 1",desc:"We connect your POS, load your products, set prices, and train your team. No downtime."},s3:{title:"Week 1",desc:"System learns the patterns -\nfirst forecasts arrive.\nStore's performance is starting to improve."}},security:{badge:"SECURITY",title:"Secure your data 24/7",description:"Our ERP built to meet global compliance standards and protect your data at every stage",certified:"Certified & Compliant With Global Standards",f1:{title:"GDPR",desc:"Our system has been developed in full compliance with GDPR requirements."},f2:{title:"Access control",desc:"Advanced access control systems, ensure your data stays secure — and always remains yours."},f3:{title:"Secure Architecture",desc:"Cloud-native infrastructure designed for high availability, performance, and enterprise-grade protection."}},pythia:{badge:"INTRODUCING PYTHIA",title:"Your Store's AI Helper",description:"Pythia isn't just a module. It's a powerful AI engine that analyses your sales data and suggests smart decisions.",c1:{title:"Predicts Demand",desc:"Knew yesterday what your customer would need tomorrow."},c2:{title:"Prevents Stockouts",desc:"Alerts you to reorder before shelves are empty."},c3:{title:"Reduces Losses",desc:"Orders only the required quantity, minimizing the amount of\nexpired goods."},s1:{label:"Prediction Accuracy",value:">90%"},s2:{label:"Expired Goods Reduction",value:"-65%"},today:"TODAY",forecast:{label:"RISING DEMAND",value:"+29% expected"}},socialProof:{badge:"Social Proof",title:"Trusted by Independent Grocers",testimonials:{0:{quote:"Since switching to Salut!, our waste has dropped by 40% and margins are up. Pythia tells us exactly what to order.",name:"Antonio Rodriguez",role:"Owner, Supermercados Paco"},1:{quote:"The setup was incredibly fast. We were running the new POS in one day. The staff loves how easy it is.",name:"Maria Garcia",role:"Manager, Fresh & Local"}}},impact:{quote:'"It\'s like adding 3 full-time employees."',description:"According to statistics, Salut! enables the average independent supermarket to save more than 8,600 hours per year, and delivers the industry's highest Return On Investment\nby minimizing Waste and preventing Stockouts.",btnStart:"Get Started",s1:{label:"Return On Investment",value:"584%",desc:"Average return on investment within the first year of using the Salut! system."},s2:{label:"Expired Goods Reduction",value:"65%",desc:"Minimize product spoilage with AI-powered demand forecasting system."},s3:{label:"Hours Saved",value:"8,600+",desc:"The amount of hours saved annually per store by automating inventory management, planning, and purchasing."},s4:{label:"Payback Period",value:"< 4 months ",valuePrefix:"< 4",valueSuffix:"months",desc:"Most supermarkets cover the cost of the system in less than four months. "}},pricing:{badge:"PRICE",title:"Connect your store now and get\naccess to all features.",subtitle:"Monthly Subscription",monthlyPrice:"",monthlyPeriod:"",annualTitle:"Annual Subscription",annualPrice:"",annualPeriod:"",sharedNotePrimary:"",sharedNoteSecondary:"",btnNote:"Cancel anytime.",bundleF1:"Sales Prediction & Inventory Management",bundleF2:"Price-Tags & Store Operations",bundleF3:"Analytical Reports",bundleF4:"POS Module",equipmentTitle:"Equipment",equipmentPrice:"€490",equipmentNote:"Required equipment set.",equipmentF1:"15.6 Inch Touch Screen",equipmentF2:"Thermal Printer",equipmentF3:"Barcode Scanner",equipmentF4:"Cash Box",optionalLabel:"Optional - the system can work with your existing equipment.",price:"€19.99",period:"/mo",note:"No hidden fees. Cancel anytime.",btnStart:"Get Started",f1:"Predictive Ordering",f2:"Inventory Auto-Replenishment",f3:"Waste Reduction Dashboard",f4:"Smart Shelf Placement",step1Title:"How many stores do you want to connect?",step2Title:"Where should we send your proposal?",stepOf:"Step {current} of {total}",freeTrialPromo:"for the first 2 months for all new users",freeTrialDisclaimer:"* Future price depends on the number of your stores. If you don't have equipment, it is purchased separately.",storeOption1:"1 store",storeOption2:"2-5 stores",storeOption3:"6-10 stores",storeOption4:"More than 10",btnNext:"Next Step",btnBack:"Back",compareTitle:"Why Salut is different",compareSalut:"Salut",compareStandard:"Standard ERP",compareFeature1:"AI Sales Prediction",compareFeature2:"Automated Inventory Replenishment",compareFeature3:"Smart Shelf Placement",compareFeature4:"Waste Reduction Analytics",compareFeature5:"All-in-one ERP System",compareFeature6:"Free Equipment Consultation"},equipmentPage:{heroBadge:"Equipment",heroTitle:"Hardware & POS Equipment for Supermarkets",heroSubtitle:"We offer complete hardware kits and POS systems for your supermarket checkout automation. Our Pro and Ultra sets include touchscreens, handheld or stationary barcode scanners, secure cash drawers, and thermal receipt printers. All equipment is fully prepared to comply with VeriFactu regulations.",description:"Explore our range of hardware solutions designed to integrate seamlessly with Salut ERP. From POS terminals to barcode scanners, we have everything you need to run your store efficiently.",supportBadge:"365 Days Support",kits:{touch:{title:"Touch Screen Terminal",desc:"A sleek, modern 15.6 inch POS touch screen terminal. Clean, minimalist aesthetic.",price:"€390",f1:"15.6 Inch Touch Screen",f2:"High Performance CPU",f3:"Built-in Customer Display"},touchScanner:{title:"Touch Screen + Scanner",desc:"Complete your checkout with a high-speed barcode scanner and our premium touch screen terminal.",price:"€490",f1:"15.6 Inch Touch Screen",f2:"Handheld Barcode Scanner",f3:"Fast USB Connection"},touchScannerDrawer:{title:"Complete Checkout Kit",desc:"The ultimate checkout experience. Touch screen terminal, barcode scanner, and a secure cash drawer.",price:"€590",f1:"15.6 Inch Touch Screen",f2:"Barcode Scanner",f3:"Secure Cash Drawer"}},product:{features:"Key Features",specs:"Technical Specifications",contactSales:"Contact Sales",backToEquipment:"Back to Equipment",viewOffer:"View Offer"},pro:{badge:"VeriFactu Ready",title:"Pro",desc:"A powerful and comprehensive hardware kit for medium to high traffic supermarkets.",f1:'15.6" Touch Screen',f2:"Computer & components",f3:"Handheld/stationary scanner",f4:"Cash drawer",f5:"+ additional customer display",price:"459€",oldPrice:"640€",btn:"Order Pro",fineprint:'Includes: 15.6" touch screen, computer with components, handheld/stationary barcode scanner, secure cash drawer, and additional customer-facing display.'},ultra:{badge:"VeriFactu Ready",title:"Ultra",desc:"Our premium dual-screen setup, featuring an elegant all-in-one terminal for the ultimate checkout efficiency.",f1:"Premium all-in-one terminal (dual screens)",f2:"Handheld/stationary scanner",f3:"Cash drawer",price:"499€",oldPrice:"655€",btn:"Order Ultra",fineprint:"Includes: Premium dual-screen all-in-one POS terminal, handheld/stationary barcode scanner, and secure cash drawer."}},howItWorks:{badge:"THE PROCESS",title:"How Salut Works",description:"A seamless transition to an AI-powered supermarket. Connect your register, manage your catalog, and automate your operations in 24 hours.",step1:{number:"Step 1",title:"Connect Your Store",desc:"We connect seamlessly with your store. You can use your existing hardware and POS equipment or purchase a complete ready-to-go kit from us.",bullets:["Use your existing checkout PC, laptop, or tablet","Compatible with standard USB/Bluetooth barcode scanners","Direct integration with scales (Dibal, Bizerba, CAS)","Optional ready-to-use plug-and-play hardware kit"]},step2:{number:"Step 2",title:"Import Your Catalog",desc:"We import your products, prices, and barcodes into our supermarket software database to create a smart product matrix optimized for your daily operations.",bullets:["Full catalog migration in under 24 hours","Automatic mapping of existing barcodes","Supplier contact list and price sheets loaded","Smart categories and tax rates configured"]},step3:{number:"Step 3",title:"ERP Live Operations",desc:"Salut ERP and POS software begins running. Change product prices instantly, print tickets and receipts for your store, and monitor performance in real-time.",bullets:["100% offline-capable POS checkout interface","Instant price updates across all terminals","VeriFactu compliant receipt generation with QR","Real-time stock deduction upon sale"]},step4:{number:"Step 4",title:"Grow & Optimize",desc:"Watch your margins grow as waste is minimized and out-of-stocks become a thing of the past. You get full visibility and control over your entire operation.",bullets:["AI-powered purchase order recommendations","Expiration date tracking and markdown management","Out-of-stock risk prevention alerts","Live gross margin and store performance dashboard"]},faq:{badge:"FAQ",title:"Frequently Asked Questions",description:"Everything you need to know about setting up Salut in your store.",q1:{q:"What is the best software for independent supermarkets?",a:"The best supermarket software combines ease of use at checkout with deep inventory management. Salut provides a web-based supermarket POS that works offline, automates orders using AI, and complies with local tax regulations."},q2:{q:"Is Salut an open source or free supermarket software?",a:"No, Salut is a professional SaaS ERP. However, we offer a 14-day free trial with no credit card required, allowing you to experience the impact of AI on your margins risk-free."},q3:{q:"How does Salut import product data from my old system?",a:"Our migration team handles everything. We import your articles, barcodes, and suppliers in less than 24 hours, meaning your store transition is smooth and doesn't interrupt your sales."},q4:{q:"Do you offer setup and hardware support locally?",a:"Yes, we support remote setup and physical installation. Our team assists with scanner connection, scale integration, and localized POS monitoring to get you running quickly."}}},verifactuPage:{heroBadge:"TPV READY FOR HACIENDA",heroTitle:"Comply with Verifactu for free from the first ticket: your POS is ready for Hacienda",heroSubtitle:"Worried about the new Hacienda regulations? Many look for free supermarket software to avoid expenses, but complying with the law often comes with hidden costs. With our solution, adapting to Verifactu costs nothing extra and requires zero coding. You keep selling; we handle the technical side.",whatIsIt:{title:"What is Verifactu?",content1:"Verifactu is the new billing control system implemented by the Spanish Tax Agency to prevent tax fraud. Simply put: your POS or management software must record every sale in an unalterable way and securely send the info to Hacienda.",content2:"If you're asking 'what is Verifactu', the short answer is: it's the law that changes how you issue tickets and invoices. From now on, your sales system must generate records with an electronic signature, consecutive numbering, and a time stamp so no one can modify them later.",content3:"It's not a program you download from Hacienda's website. It is a Verifactu regulation that your billing software must comply with to keep you protected during an inspection."},claves:{title:"Key aspects of the Verifactu regulation and how it affects your billing",p1:"The Verifactu regulation establishes clear rules on how your billing must work. These are the three obligations you must know:",items:[{title:"Unalterable record",desc:"Each ticket or invoice is saved with a timestamp and digital signature. It cannot be deleted or edited after being issued."},{title:"Consecutive numbering",desc:"Documents must follow a consecutive order without gaps or duplicates."},{title:"Sent to Hacienda",desc:"The information must be available to the Tax Agency in the format and timeframe required by law."}],p2:"What does this mean for your daily business? If you use an old POS, you might face issues during an inspection. The good news is that with our solution, your billing complies with these three points from the first ticket."},solution:{title:"The solution: Salut! ERP",description1:"If you're looking for a professional system to get started, you will love our platform. Our platform is designed for businesses like yours: modern, fast, and straightforward. And now, it includes full Verifactu adaptation at no extra cost.",description2:"This is what you get when you create your account:",description3:"We don't charge you extra to comply with the law. While our core system is a premium subscription, your Verifactu compliance is always included. No extra costs or hidden fees."},faq:{title:"Impact of Verifactu on Autónomos",subtitle:"If you're self-employed, this regulation can be stressful. We clarify the most common fears:",q1:{q:"Do I need to hire an IT specialist?",a:"No. Our software comes pre-configured to comply with the regulations. You don't need to know programming or ask for quotes."},q2:{q:"Is the Verifactu compliance going to cost me money?",a:"No. We offer the Verifactu adaptation for free within your regular subscription. While our software is a paid service, there are no fine print or hidden paywalls for legal compliance."},q3:{q:"What if Hacienda inspects me?",a:"With us, every sale is recorded with the time stamp and signature required by law. In an inspection, you prove compliance in seconds."}},ctaTitle:"Start today: your first Verifactu-compliant ticket in less than 5 minutes",ctaDesc:"Stop worrying about deadlines and fines. Whether you were looking for free supermarket software or a premium ERP, you can start with our platform today. Complying with the law is as simple as opening your POS and selling. Create your account now.",ctaButton:"Get Started",features:["Verifactu-ready POS from day one","Integrated stock management: control inventory as you sell","Automatic backups: your data is safe in the cloud","Human support: we answer your questions"]},faq:{badge:"FAQ",title:"Frequently Asked Questions",description:"We've heard them all. Here are the ones that matter most.",q1:{q:"Can Salut! replace my current POS system?",a:"Absolutely. Salut! is designed as a complete all-in-one ERP, which includes a modern, high-speed Point of Sale interface that works offline and syncs instantly with your inventory."},q2:{q:"Do I need to buy new hardware?",a:"In most cases, no. Salut! runs in the browser and is compatible with standard barcode scanners, receipt printers, and touch screens. We also offer a dedicated hardware kit if you're starting fresh."},q3:{q:"How does the AI inventory prediction work?",a:"Pythia, our AI engine, analyzes your sales history, local events, and even weather patterns to predict exactly what you need to order. It spots trends before they happen, reducing waste and preventing stockouts."},q4:{q:"How long does it take to get set up?",a:"We can get your store migrated and running in as little as 24 hours. Our team handles the data import from your old system so you don't have to manually re-enter products."},q5:{q:"Is my data secure?",a:"Yes. We use enterprise-grade encryption for all data storage and transmission. Your business data is backed up automatically every hour."}},contact:{badge:"CONTACT US",title:"Let's Get In Touch.",description:"Fill out the form below or use our quick contacts to reach out directly.",whatsapp:"WhatsApp",copied:"Copied!",phone:"Phone",email:"Email",telegram:"Telegram",orSend:"Or reach us directly",nameLabel:"Full Name",namePlaceholder:"Enter your full name",storeAddressLabel:"Store Address",storeAddressPlaceholder:"Enter your store address",contactMethodLabel:"Preferred contact method",contactMethodPlaceholder:"Select your preferred contact method",phoneLabel:"Phone number",phonePlaceholder:"Enter your phone number",phoneRequired:"Enter a phone number.",telegramLabel:"Telegram Username",telegramPlaceholder:"@username",telegramRequired:"Enter your Telegram username.",emailLabel:"Email Address",emailPlaceholder:"Enter your email address",emailRequired:"Enter an email address.",msgLabel:"Message",msgOptional:"(Optional)",msgPlaceholder:"Enter your message",btnSubmit:"Submit Form",submitting:"Sending...",successTitle:"Success!",submitSuccess:"Message sent. We'll get back to you soon.",submitError:"Couldn't send your message. Please try again.",contactMethodRequired:"Select your preferred contact method."},cta:{heading:"Ready to Modernize?",body:"Join over 500+ independent supermarkets using Salut!",button:"Get Free Demo",trialNote:"No credit card required • 14-day free trial"},legal:{common:{contents:"On this page",backHome:"Back to homepage",lastUpdatedLabel:"Last updated",lastUpdatedValue:"March 9, 2026",reviewNoticeTitle:"Placeholder legal content",reviewNoticeBody:"This page is a temporary scaffold prepared for legal review. Replace this copy with counsel-approved language before treating it as the final policy or agreement."},privacy:{eyebrow:"Privacy policy",title:"How Salut handles information today.",intro:"This placeholder privacy policy explains the categories of information we expect to collect and how we expect to use it once the final legal text is approved.",sections:{informationWeCollect:{heading:"Information we collect",body:"Salut may collect account details, store setup data, usage events, support conversations, and technical identifiers needed to operate the platform. This placeholder section exists to reserve the structure for the final legally approved data inventory."},howWeUseInformation:{heading:"How we use information",body:"We expect to use collected information to provide the service, maintain account security, support onboarding, improve product performance, and communicate important service updates. Final copy should confirm the lawful bases and exact operational purposes."},dataSharing:{heading:"Data sharing",body:"Salut may share limited data with infrastructure, analytics, communications, or support vendors that help deliver the service. The final policy should specify when data is shared, why it is shared, and what contractual safeguards apply."},dataRetention:{heading:"Data retention",body:"This placeholder assumes account and operational records are retained only for as long as needed to deliver the service, comply with legal obligations, and resolve disputes. The production version should define concrete retention timelines and deletion workflows."},yourRights:{heading:"Your rights",body:"Depending on the jurisdiction, users may have rights to access, correct, export, restrict, or delete personal information. Replace this paragraph with the exact rights, exceptions, and submission process confirmed by legal counsel."},contact:{heading:"Contact",body:"For privacy questions, data requests, or complaints, the final policy should point users to the approved contact channel and response process. Until then, treat this section as a placeholder for the definitive support and legal contact details."}}},terms:{eyebrow:"Terms of service",title:"The rules for using Salut.",intro:"This placeholder terms page outlines the main contractual areas that Salut expects to cover once the final terms are reviewed and approved.",sections:{acceptanceOfTerms:{heading:"Acceptance of terms",body:"By accessing or using Salut, customers are expected to agree to the service terms, applicable policies, and any order forms or commercial agreements. The final language should define who is contracting, when acceptance occurs, and which documents control."},permittedUse:{heading:"Permitted use",body:"Salut is intended for lawful business use connected to retail operations. Final terms should describe acceptable use, prohibited activities, and any product-specific limitations on automation, reverse engineering, or misuse."},accountResponsibilities:{heading:"Account responsibilities",body:"Customers are expected to keep credentials secure, manage user permissions carefully, and ensure submitted information is accurate. Counsel-approved terms should also clarify responsibility for user activity and notice requirements for unauthorized access."},serviceAvailability:{heading:"Service availability",body:"Salut aims to keep the service available and reliable, but the production terms should explain maintenance windows, planned changes, outage handling, and whether uptime commitments are included elsewhere."},intellectualProperty:{heading:"Intellectual property",body:"The final agreement should confirm Salut retains ownership of the platform, software, branding, and documentation, while customers retain ownership of their own business data except where limited rights are needed to operate the service."},limitationOfLiability:{heading:"Limitation of liability",body:"This placeholder reserves space for the commercial risk allocation, including warranty disclaimers, liability caps, and excluded damages. Replace it with the precise language approved for the applicable markets and contract model."},contact:{heading:"Contact",body:"The final terms should identify the correct legal or support contact for notices, disputes, and contractual questions. Until approved, this section remains a structural placeholder only."}}}},blog:{sectionTitle:"Latest from the Blog",sectionSubtitle:"Insights and strategies for modern grocery retail.",readMore:"Read article",viewAll:"View all posts"},inactivityModal:{badge:"LIMITED OFFER",title:"Digitize your business today",description:"Join over 500 businesses already using Salut! to manage their operations.",question:"Leaving without trying it?",subtitle:"You're one click away from trying the fastest ERP on the market.",perk1Title:"30 Days Completely Free",perk1Desc:"No fine print. If you don't like it, you pay nothing.",perk2:"Immediate access",perk3:"No credit card required",btnPrimary:"Try Salut for Free",btnSecondary:"No, I prefer managing my business manually"},softwareTpvPage:{heroBadge:"New: POS Software with VeriFactu",heroTitle:"Supermarket POS Software",heroTitleTagline:"Total Control of Your Cashier, Stock & Billing in the Cloud",heroSubtitle:"Forget obsolete programs. Salut is the modern supermarket software that runs in your browser: setup in 24 hours, supermarket software with integrated AI, and POS with VeriFactu ready for 2026 regulations. All without installing anything.",heroCtaPrimary:"Get Started",heroCtaSecondary:"View compatible equipment",heroTrustLine:"No credit card required · Guaranteed VeriFactu compliance · English support",posSection:{title:"Fast POS Software: Sell More and Without Interruptions",item1Title:"Offline POS: The Register Never Stops",item1Desc:"If the Internet drops, you keep selling. This supermarket cash register software saves tickets locally, controls scales, and opens the drawer. Everything syncs when the network is back, without data loss.",item2Title:"Automatic Cash Reconciliation in 2 Minutes",item2Desc:"Forget counting cash manually. The cash up is automatic: reconcile sales, cash, and card payments without errors or wasted time. Less administrative work and more time for your customers."},stockSection:{title:"Smart Inventory: Supermarket Management Software with AI",desc:"Control your warehouse like the big chains. Salut updates stock levels in real time, manages batches, and automatically prevents stockouts.",item1Title:"Expiration Dates and Batches Under Control",item1Desc:"Alerts before yogurts, cheeses, or juices expire. Apply automatic discounts at checkout to save your margin instead of throwing away inventory. Batch management that protects your profitability.",item2Title:"Automated Supplier Orders",item2Desc:"Our AI Pythia analyzes sales history to calculate exactly how much to order. As supermarket ERP software, it eliminates empty shelves and excess stock that only takes up space.",item3Title:"Real-Time Stock Synchronization",item3Desc:"Each sale at checkout instantly deducts units from the warehouse. Avoid surprise out-of-stock situations and inventory discrepancies that cost you so much."},labelsSection:{title:"Print Labels and Receipts in the Right Format",subtitle:"Quick printing for all your store products. No manual errors or outdated tags.",desc1:"Our software automatically prepares and prints labels and receipts in the most suitable format for all your goods. When you update a price or complete a sale, Salut adds it to the print queue instantly.",desc2:"Compatible with any thermal printer on the market. High-resolution barcodes that scan the first time on your POS.",cardDesignTitle:"Price Tag Preview",cardPrintQueue:"Print Queue",cardQueueStatus:"Printing...",labelRegular:"Regular Price",labelPromo:"Special Offer",labelClearance:"Clearance"},lawSection:{badge:"Spain Anti-Fraud Law",titlePart1:"Prepare your POS for VeriFactu and",titlePart2:"avoid fines of up to €50,000",subtitle:"Starting January 1, 2027, the AEAT mandates certified POS systems that transmit invoice records in real time. Salut is fully compliant out of the box.",promo:"MIGRATION SPECIAL: 100% FREE SETUP",cta:"Avoid penalties today",note:"VeriFactu certification included in all plans with no extra fees"},hardwareSection:{title:"Plug & Play with Your Existing Hardware—Or Get a Complete Ready-to-Go Kit",desc:"Salut is compatible with any equipment. In case you don't have it, we sell POS terminals, scanners, etc.",bullet1:"Complete POS Terminals (Touchscreens & CPUs)",bullet2:"Thermal Ticket & Receipt Printers",bullet3:"Barcode & QR Scanners",bullet4:"Certified Weight Scales & Cash Drawers",ctaButton:"View equipment kits"},faq:{title:"Frequently Asked Questions about Supermarket Software",q1:{q:"What exactly does the AEAT require from supermarket POS software?",a:"The VeriFactu regulations require the software to guarantee the integrity, traceability, and inalterability of billing records. Each ticket must carry a QR code, a recognized electronic signature, and a unique serial number. In addition, the system must prevent the modification or deletion of already issued documents. Salut meets all these requirements natively, without complex configurations."},q2:{q:"How does the program connect with scales and scanners?",a:"Salut integrates directly with weighing scales (Dibal, Bizerba, CAS) using standard protocols. When you weigh a product, the scale generates a barcode with weight and price that the POS reads when scanned. Scanners work via USB or Bluetooth without complicated drivers. It is a truly plug & play system."},q3:{q:"How long does it take to migrate my product database?",a:"Our support team completes the import of your items, prices, barcodes, and suppliers in less than 24 hours. We work with the backup from your old program and configure everything before you open the store the next day. The transition is seamless: you don't lose a single sale."},q4:{q:"What happens if the Internet goes down in my store?",a:"Salut works in offline mode. The checkout remains operational, prints tickets, opens the cash drawer, and controls stock locally. When the connection returns, the system automatically synchronizes all sales, updating inventories and sending tax data to the AEAT. Your customers won't even notice the interruption."}},widgets:{receipt:{title:"Fast Receipt Printer",status:"PRINTING RECEIPT...",itemMilk:"WHOLE MILK 1L",itemBread:"SLICED BREAD",itemPasta:"PASTA GALLO",subtotal:"SUBTOTAL",tax:"TAX (10%)",total:"TOTAL",compliant:"VERIFACTU COMPLIANT"},expiration:{title:"Expiration Alerts",yogurt:"Skimmed Yogurt",cheese:"Soft Cheese",juice:"Orange Juice"},seal:{pathText:"• AEAT CERTIFIED SYSTEM • VERIFACTU 2026",certified:"CERTIFIED"}}},footer:{slogan:"The AI-powered supermarket ERP built for growth.",product:"Product",legal:"Legal",blog:"Blog",privacy:"Privacy Policy",terms:"Terms of Service",rights:"© {year} Salut! Systems. All rights reserved."},impresoraTicketsPage:{heroBadge:"TPV Receipt Printer",heroTitle:"Receipt & Price Tag Printers for Supermarkets",heroTitleTagline:"High-Speed Thermal Receipt Printing & Barcode Label Layouts",heroSubtitle:"Complete cashier integration. Print customer tickets instantly and automate price label generation for all inventory items in one click.",heroCtaPrimary:"Get Started",heroCtaSecondary:"See all ERP benefits",heroTrustLine:"Fully compatible with standard thermal printers · VeriFactu Compliant · Plug & Play Setup",automationBadge:"Automatic Pricing",automationTitle:"Automatic Price Tag Printing",automationSubtitle:"Say goodbye to manual price tags. The moment you register or update a product in the Salut ERP, its barcode and price tag are automatically generated and queued for printing.",automationDesc1:"Creating labels for hundreds of products manually is a waste of valuable time. Salut automates the entire flow so you can print beautiful, standardized shelf tags instantly.",automationDesc2:"Whether you run standard prices, promotional pricing, or clearance markdowns, Salut format layouts adapt automatically with accurate barcodes, VAT specifications, and clean layouts.",statBadge:"Sales Impact",statTitle:"Boost Daily Sales by 20% to 30%",statDesc1:"Our analytics show that having clear, updated price tags on supermarket shelves directly boosts customer purchase intent.",statDesc2:"This effect is particularly strong in the alcohol and beverages section, where adding accurate price tags increases daily sales of those products by 20% to 30%. Never lose a customer due to missing price labels again.",hardwareBadge:"Hardware Compatibility",hardwareTitle:"Compatible with Any Thermal Printer",hardwareDesc:"Salut connects seamlessly with your existing hardware. If you already have a ticket printer at your checkout, it will work out of the box. No special drivers required.",hardwareBullet1:"Standard 80mm & 58mm thermal receipt printers",hardwareBullet2:"Zebra, Epson, Star Micronics, and Bixolon brands supported",hardwareBullet3:"Connection via USB, Ethernet (LAN), Wi-Fi, or Bluetooth",hardwareBullet4:"VeriFactu compliant tickets with AEAT certified signatures and QR codes"},comparativasPage:{heroBadge:"Compare Salut",heroTitle:"The best supermarket POS software: Salut vs the Rest",heroSubtitle:"Why independent supermarkets are migrating from outdated systems and generic ERPs to Salut's AI.",traditionalTitle:"Salut vs Traditional & Legacy Software",traditionalDesc:"Classic programs like Gesvent, Verial, or TPV GLOP have been the standard for years, but they require local installations, expensive servers, and lack AI forecasting.",traditionalAdvantage:"Salut's Advantage: 100% in the cloud, automatic updates, no local servers, and demand prediction via AI (Pythia).",genericTitle:"Salut vs Generic Accounting ERPs",genericDesc:"Searching for Odoo or Holded is common to stay compliant, but these are generic ERPs that require expensive customizations for retail.",genericAdvantage:"Salut's Advantage: Built exclusively for supermarkets. We natively handle perishable goods, ultra-fast POS, and shelf stock control.",tableTitle:"The Ultimate Comparison",tableCols:{salut:"Salut ERP",traditional:"Traditional Software",generic:"Generic ERP"},tableRows:{ai:"AI Demand Prediction (Pythia)",focus:"100% Supermarket Focus",cloud:"No Local Servers (Cloud)",ui:"Modern & Intuitive Interface"},btnSoftwareTpv:"Read more about Salut",verifactuTitle:"VeriFactu Compliance Included",verifactuDesc:"The new anti-fraud rules are strict. Salut guarantees your POS is connected and complies with the Tax Agency from minute one. It is the easiest compliant POS to implement.",btnVerifactu:"Read more about VeriFactu",migrationTitle:"Migration & Transition",migrationDesc:"Is it hard to migrate my data? Not at all. We handle the entire import process of your catalog and stock seamlessly.",btnMigration:"See How It Works",ctaTitle:"Don't stay in the past with systems that limit your growth.",ctaButton:"Start with Salut today"}},ES:{nav:{home:"Inicio",about:"About",features:"Funciones",pythia:"Pythia IA",price:"Precios",faq:"Preguntas Frecuentes",blog:"Blog",getStarted:"Comenzar",howItWorks:"Cómo Funciona",equipment:"Equipamiento",product:"Producto",resources:"Recursos",softwareTpv:"Software TPV Supermercado",comparativas:"Comparativas",contact:"Contacto",impresoraTickets:"Impresora de Tickets",verifactu:"VeriFactu"},hero:{badge:"Nuevo: Predicción de Demanda con IA 🚀",titleLine1:"Software para Supermercados",titleLine2:"con Verifactu.",description1:"Salut es el software TPV supermercado definitivo. Reúne toda tu operativa, desde el software para caja registradora hasta la gestión de stock y personal.",description2:" Implementado en un solo día.",btnStart:"Empieza la prueba gratis",btnEquipment:"Ver nuestro equipamiento",compatibleWith:"Compatible con",verifactu:"Verifactu",playVideo:"Reproducir video"},solution:{badge:"La Solución",title:"El mejor software de gestión para supermercados",description:"Salut! es un software ERP para supermercados que combina todo lo que necesitas en una plataforma fácil de usar. Tu software para TPV, inventario y analítica sin hojas de cálculo.",pos:"TPV",inventory:"Inventario",purchasing:"Compras",analytics:"Analítica",staff:"Personal"},problem:{badge:"ACERCA DE",title:"Impulsando las ventas de los supermercados con tecnologías inteligentes",description:"Salut! ofrece un software para supermercado independiente con las herramientas de las grandes cadenas, ayudando a reducir roturas de stock mediante un software para TPV ágil y moderno.",btnDemo:"Comenzar",f1:{title:"Reducir roturas de stock",desc:"La predicción de demanda con IA y la reposición automatizada mantienen las estanterías llenas y hacen que los clientes vuelvan. Captura más ventas y no pierdas demanda."},f2:{title:"Minimizar la merma y proteger los márgenes",desc:"Controla las fechas de caducidad, optimiza la rotación del inventario y reduce pérdidas para mejorar la rentabilidad."},f3:{title:"Aumentar la eficiencia operativa",desc:"Automatiza compras, inventario e informes para ahorrar tiempo, reducir errores y dar más poder a tu equipo."},f4:{title:"Un sistema unificado",desc:"TPV, inventario, contabilidad y analítica en una sola plataforma. Menos complejidad. Más visibilidad. Control total."}},features:{title:"La solución todo en uno",description:"Salut! combina todo lo que necesitas para gestionar tu supermercado en una plataforma fácil de usar. Se acabaron las hojas de cálculo, los sistemas desconectados y\nlas operaciones manuales.",f1:{title:"Inteligencia de demanda con IA",desc:"Predice la demanda con precisión mediante modelos adaptativos de aprendizaje automático entrenados con tu historial de ventas.",highlight:">90% de precisión"},f2:{title:"Automatización inteligente de proveedores",desc:"Genera pedidos de compra automáticamente a partir de la velocidad de venta en tiempo real.",highlight:"Ahorra 12 h/sem"},f3:{title:"Control de inventario en vivo",desc:"Supervisa los niveles de stock con alertas predictivas de bajo inventario y disparadores de reposición.",highlight:"Cero roturas"},f4:{title:"Inteligencia de negocio",desc:"Convierte los datos operativos en información útil mediante paneles e informes en tiempo real.",highlight:"P&G al instante"}},steps:{badge:"RAPIDEZ",title:"Un día para transformarlo todo",description:"No creemos en implantaciones largas. Tu tienda estará funcionando mañana,\nno el mes que viene.",btnStart:"Comenzar",s1:{title:"Hoy",desc:"Reserva una demo y descubre cómo Salut se adapta a tu\ntienda."},s2:{title:"Día 1",desc:"Conectamos tu TPV, cargamos tus productos, fijamos los precios y formamos a tu equipo. Sin paradas."},s3:{title:"Semana 1",desc:"El sistema aprende los patrones:\nllegan las primeras previsiones.\nEl rendimiento de la tienda empieza a mejorar."}},security:{badge:"SEGURIDAD",title:"Protege tus datos 24/7",description:"Nuestro ERP está diseñado para cumplir con los estándares globales de cumplimiento y proteger tus datos en cada etapa.",certified:"Certificado y alineado con estándares globales",f1:{title:"RGPD",desc:"Nuestro sistema ha sido desarrollado en pleno cumplimiento de los requisitos del RGPD."},f2:{title:"Control de acceso",desc:"Sistemas avanzados de control de acceso que garantizan que tus datos estén seguros y sigan siendo tuyos."},f3:{title:"Arquitectura segura",desc:"Infraestructura cloud nativa diseñada para alta disponibilidad, rendimiento y protección de nivel empresarial."}},pythia:{badge:"PRESENTANDO A PYTHIA",title:"La ayuda de IA de tu tienda",description:"Pythia no es solo un módulo. Es un potente motor de IA que analiza tus datos de ventas y sugiere decisiones inteligentes.",c1:{title:"Predice la demanda",desc:"Ayer ya sabía lo que tu cliente necesitaría mañana."},c2:{title:"Evita las roturas de stock",desc:"Te avisa para reponer antes de que falte producto."},c3:{title:"Reduce las pérdidas",desc:"Pide solo la cantidad necesaria, minimizando la cantidad de\nproductos caducados."},s1:{label:"Precisión de la predicción",value:">90%"},s2:{label:"Reducción de productos caducados",value:"-65%"},today:"HOY",forecast:{label:"DEMANDA AL ALZA",value:"+29% esperado"}},socialProof:{badge:"Prueba Social",title:"Con la confianza de supermercados independientes",testimonials:{0:{quote:"Desde que usamos Salut!, la merma ha bajado un 40% y el margen ha mejorado. Pythia nos dice qué pedir y cuándo hacerlo.",name:"Antonio Rodriguez",role:"Propietario, Supermercados Paco"},1:{quote:"La implantación fue rapidísima. En un día teníamos el nuevo TPV funcionando. El equipo se adaptó enseguida.",name:"Maria Garcia",role:"Gerente, Fresh & Local"}}},impact:{quote:'"Es como añadir 3 empleados a tiempo completo."',description:"Según las estadísticas, Salut! permite al supermercado independiente medio ahorrar más de 8.600 horas al año y ofrece el mayor retorno de la inversión del sector\nal minimizar las mermas y evitar las roturas de stock.",btnStart:"Comenzar",s1:{label:"Retorno de la inversión",value:"584%",desc:"Retorno medio de la inversión durante el primer año de uso del sistema Salut!."},s2:{label:"Reducción de productos caducados",value:"65%",desc:"Minimiza el deterioro de los productos con un sistema de predicción de demanda basado en IA."},s3:{label:"Horas ahorradas",value:"8.600+",desc:"Cantidad de horas ahorradas al año por tienda al automatizar la gestión del inventario, la planificación y las compras."},s4:{label:"Periodo de amortización",value:"< 4 meses ",valuePrefix:"< 4",valueSuffix:"meses",desc:"La mayoría de los supermercados cubren el coste del sistema en menos de cuatro meses. "}},pricing:{badge:"PRICE",title:"Conecta tu tienda ahora y obtén\nacceso a todas las funcionalidades.",subtitle:"Suscripción mensual",monthlyPrice:"",monthlyPeriod:"",annualTitle:"Suscripción anual",annualPrice:"",annualPeriod:"",sharedNotePrimary:"",sharedNoteSecondary:"",btnNote:"Cancela cuando quieras.",bundleF1:"Predicción de ventas y gestión del inventario",bundleF2:"Etiquetas de precio y operaciones de tienda",bundleF3:"Informes analíticos",bundleF4:"Módulo de TPV",equipmentTitle:"Equipamiento",equipmentPrice:"€490",equipmentNote:"Conjunto de equipamiento necesario.",equipmentF1:"Pantalla táctil de 15,6 pulgadas",equipmentF2:"Impresora térmica",equipmentF3:"Escáner de código de barras",equipmentF4:"Cajón portamonedas",optionalLabel:"Opcional - el sistema puede funcionar con su equipamiento existente.",price:"€19.99",period:"/mes",note:"Sin tarifas ocultas. Cancela cuando quieras.",btnStart:"Empieza la prueba gratis",f1:"Pedidos predictivos",f2:"Reposición automática de inventario",f3:"Panel de reducción de merma",f4:"Colocación inteligente de estanterías",step1Title:"¿Cuántas tiendas quieres conectar?",step2Title:"¿A dónde enviamos tu propuesta?",stepOf:"Paso {current} de {total}",freeTrialPromo:"los primeros 2 meses para todos los nuevos usuarios",freeTrialDisclaimer:"* El precio futuro depende del número de sus tiendas. Si no dispone de equipo, se adquiere por separado.",storeOption1:"1 tienda",storeOption2:"2-5 tiendas",storeOption3:"6-10 tiendas",storeOption4:"Más de 10",btnNext:"Siguiente paso",btnBack:"Atrás",compareTitle:"Por qué Salut es diferente",compareSalut:"Salut",compareStandard:"ERP Estándar",compareFeature1:"Predicción de Ventas por IA",compareFeature2:"Reposición Automática",compareFeature3:"Colocación Inteligente en Estantes",compareFeature5:"Sistema ERP Todo-en-Uno",compareFeature6:"Consulta Gratuita de Equipos"},equipmentPage:{heroBadge:"Equipamiento",heroTitle:"Hardware y Equipamiento TPV para Supermercados",heroSubtitle:"Ofrecemos kits de hardware y sistemas TPV completos para la automatización de la caja de tu supermercado. Nuestros conjuntos Pro y Ultra incluyen terminales con pantalla táctil, lectores de códigos de barras manuales o fijos, cajones portamonedas seguros e impresoras térmicas de tickets. Todo el equipamiento está preparado para cumplir con la normativa VeriFactu.",description:"Explora nuestra gama de soluciones de hardware diseñadas para integrarse perfectamente con Salut ERP. Desde terminales TPV hasta escáneres de códigos de barras, tenemos todo lo que necesitas para gestionar tu tienda de forma eficiente.",supportBadge:"Soporte 365 días",kits:{touch:{title:"Terminal de Pantalla Táctil",desc:"Un terminal TPV táctil de 15,6 pulgadas elegante y moderno. Estética limpia y minimalista.",price:"€390",f1:"Pantalla táctil de 15,6 pulgadas",f2:"CPU de alto rendimiento",f3:"Visor de cliente integrado"},touchScanner:{title:"Pantalla Táctil + Escáner",desc:"Completa tu punto de venta con un escáner de códigos de barras de alta velocidad y nuestro terminal táctil premium.",price:"€490",f1:"Pantalla táctil de 15,6 pulgadas",f2:"Escáner de código de barras manual",f3:"Conexión USB rápida"},touchScannerDrawer:{title:"Kit de Caja Completo",desc:"La experiencia de caja definitiva. Terminal táctil, escáner de código de barras y cajón portamonedas seguro.",price:"€590",f1:"Pantalla táctil de 15,6 pulgadas",f2:"Escáner de código de barras",f3:"Cajón portamonedas seguro"}},product:{features:"Características Principales",specs:"Especificaciones Técnicas",contactSales:"Contactar a Ventas",backToEquipment:"Volver a Equipamiento",viewOffer:"Ver Oferta"},pro:{badge:"Listo para VeriFactu",title:"Pro",desc:"Una configuración potente y fiable para la mayoría de los supermercados. Incluye un ordenador de alto rendimiento y todos los periféricos esenciales.",f1:'Pantalla táctil de 15,6"',f2:"Ordenador y componentes",f3:"Escáner manual/fijo",f4:"Cajón portamonedas",f5:"+ pantalla adicional para el cliente",price:"459€",oldPrice:"640€",btn:"Solicitar Pro",fineprint:'Incluye: Pantalla táctil de 15,6", ordenador con componentes, escáner manual/fijo, cajón portamonedas y pantalla adicional para mostrar al cliente.'},ultra:{badge:"Listo para VeriFactu",title:"Ultra",desc:"Nuestra solución de caja premium todo en uno. Cuenta con un moderno terminal táctil con pantallas duales integradas para la mejor experiencia.",f1:"Terminal monobloque premium con doble pantalla",f2:"Escáner manual/fijo",f3:"Cajón portamonedas",price:"499€",oldPrice:"655€",btn:"Solicitar Ultra",fineprint:"Incluye: Terminal TPV monobloque premium de doble pantalla, escáner manual/fijo y cajón portamonedas."}},howItWorks:{badge:"EL PROCESO",title:"Cómo funciona el mejor software para supermercados",description:"Descubre el proceso sencillo para implementar nuestro software supermercado y optimizar tus ventas. Desde conectar tu caja registradora hasta la automatización con IA en 24 horas.",step1:{number:"Paso 1",title:"Conexión de la tienda",desc:"Conectamos tu tienda con nuestro software de supermercado. Puedes utilizar tu propio equipamiento de TPV existente o adquirir uno de nuestros kits completos, incluyendo un software para caja registradora supermercado listo para vender.",bullets:["Usa tu PC, ordenador portátil o tablet existente","Compatible con escáneres de códigos de barras estándar USB/Bluetooth","Integración directa con balanzas (Dibal, Bizerba, CAS)","Kit de hardware completo plug-and-play opcional"]},step2:{number:"Paso 2",title:"Matriz de artículos",desc:"Cargamos todos tus productos y códigos de barras en la base de datos de nuestro software para supermercados. Nuestra herramienta actúa como un potente supermercado software, creando una matriz de inventario inteligente optimizada para tu día a día.",bullets:["Migración completa del catálogo en menos de 24 horas","Mapeo automático de códigos de barras existentes","Carga de lista de proveedores y tarifas","Configuración de categorías e IVA simplificada"]},step3:{number:"Paso 3",title:"ERP en tiempo real",desc:"El software ERP y software tpv supermercado de Salut comienza a funcionar. Este software gestion supermercados te permite cambiar precios de artículos al instante, imprimir tickets de caja y ver todos los resultados de tu tienda en tiempo real.",bullets:["Caja TPV que funciona 100% offline","Actualización de precios al instante en todas las cajas","Tickets compatibles con VeriFactu con código QR","Deducción automática de stock en cada venta"]},step4:{number:"Paso 4",title:"Crecimiento y Optimización",desc:"Observa cómo crecen tus márgenes a medida que se minimiza la merma y los quiebres de stock quedan en el pasado gracias al mejor software para supermercado. Obtén visibilidad total y control sobre toda tu operación.",bullets:["Recomendación de pedidos de compra asistida por IA","Seguimiento de caducidades y descuentos automáticos","Alertas predictivas para evitar roturas de stock","Control de márgenes y rendimiento de tienda en vivo"]},faq:{badge:"PREGUNTAS",title:"Preguntas frecuentes sobre cómo comenzar",description:"Todo lo que necesitas saber para implementar Salut en tu negocio.",q1:{q:"¿Cuál es el mejor software para supermercados independientes?",a:"El mejor software de supermercados es aquel que combina sencillez de uso en caja con potencia en el almacén. Salut ofrece un software tpv supermercado que funciona 100% offline, predice compras con IA y está adaptado a VeriFactu 2026."},q2:{q:"¿Es Salut un software libre para supermercados o tiene coste?",a:"No es un software libre para supermercados, pero ofrecemos una prueba gratuita de 14 días y el primer mes sin compromiso para que experimentes la diferencia de un sistema profesional con soporte técnico en español."},q3:{q:"¿Cómo realiza Salut la monitorización y migración desde otros sistemas?",a:"Realizamos la migración completa de tus artículos y básculas en menos de 24 horas. Si buscas un software de gestión para supermercados moderno que sustituya soluciones obsoletas, nuestro equipo se encarga de todo de principio a fin."},q4:{q:"¿Ofrecéis soporte de implantación local en Badajoz y otras provincias?",a:"Sí, realizamos implantaciones y soporte remoto y presencial en toda España. Ya sea para la integración de básculas o el soporte para software monitorización supermercados badajoz y otras regiones, nuestro equipo técnico te guiará paso a paso."}}},verifactuPage:{heroBadge:"TPV LISTO PARA HACIENDA",heroTitle:"Cumple con Verifactu gratis desde el primer ticket: tu TPV ya está listo para Hacienda",heroSubtitle:"¿Te preocupa la nueva normativa de Hacienda? Muchos buscan un software para supermercados gratis para evitar gastos, pero cumplir con la ley suele tener costes ocultos. Con nuestra solución, adaptarte a Verifactu no cuesta nada extra y no requiere que toques una sola línea de código. Tú sigues vendiendo; nosotros nos encargamos de la parte técnica.",whatIsIt:{title:"Qué es Verifactu",content1:"Verifactu es el nuevo sistema de control de facturación que la Agencia Tributaria de España ha puesto en marcha para evitar el fraude fiscal. En palabras sencillas: es la obligación de que tu TPV o software de gestión registre cada venta de forma inalterable y envíe la información a Hacienda de manera segura.",content2:'Si te preguntas "qué es Verifactu" o has buscado "Verifactu qué es", la respuesta corta es: es la ley que cambia cómo debes emitir tus tickets y facturas. Desde ahora, tu sistema de venta debe generar registros con firma electrónica, numeración correlativa y un sello de tiempo que garantice que nadie —ni siquiera tú— puede borrar o modificar una transacción a posteriori.',content3:"No es un programa que descargas de la web de Hacienda. Es un reglamento Verifactu que tu software de facturación debe cumplir para que tú estés protegido ante una inspección."},claves:{title:"Claves del reglamento Verifactu y cómo afecta a tu facturación",p1:"El reglamento Verifactu establece reglas claras sobre cómo debe funcionar tu facturación Verifactu a partir de la fecha de entrada en vigor. Estas son las tres obligaciones que debes conocer:",items:[{title:"Registro inalterable",desc:"Cada ticket o factura queda grabado con un sello de tiempo y una firma digital. No se puede borrar ni editar después de emitirse."},{title:"Numeración correlativa",desc:"Los documentos deben seguir un orden consecutivo sin saltos ni duplicados."},{title:"Envío a Hacienda",desc:"La información debe estar disponible para la Agencia Tributaria en el formato y plazos que exige la normativa."}],p2:"¿Qué significa esto en el día a día de tu negocio? Que si usas un TPV antiguo o un software que no ha sido actualizado, puedes tener problemas en una inspección. La buena noticia es que con nuestra solución, tu facturación Verifactu cumple estos tres puntos desde el momento en que emites el primer ticket. Nosotros gestionamos la firma, la numeración y el formato técnico; tú solo cobras a tu cliente."},solution:{title:"La solución: Salut! ERP",description1:"Si estás buscando un sistema profesional para empezar, te invitamos a probar nuestra plataforma. Está diseñada para comercios como el tuyo: moderna, rápida y sin sorpresas. Y además, incluye la adaptación completa a Verifactu gratis en todos los planes.",description2:"Esto es lo que obtienes al crear tu cuenta:",description3:"No cobramos extras por cumplir la ley. La adaptación a Verifactu está incluida de serie. En tu suscripción habitual, siempre estarás cubierto sin sorpresas ni módulos adicionales."},faq:{title:"Impacto de Verifactu en Autónomos",subtitle:"Si eres autónomo, es normal que esta normativa te genere estrés. Los buscadores de Google se llenan de consultas sobre Verifactu autónomos porque muchos trabajadores por cuenta propia temen que adaptar su sistema les suponga un coste técnico o económico. Aquí te aclaramos los miedos más comunes:",q1:{q:"¿Tengo que contratar a un informático?",a:"No. Nuestro software ya viene configurado para cumplir la normativa. No necesitas saber de programación ni pedir presupuestos a terceros."},q2:{q:"¿La adaptación a Verifactu me va a costar dinero extra?",a:"No. Te ofrecemos la adaptación a Verifactu gratis dentro de tu plan. Aunque nuestra plataforma es de pago, no hay letra pequeña ni te cobraremos módulos adicionales por cumplir la ley."},q3:{q:"¿Y si Hacienda me revisa?",a:"Con nosotros, cada venta queda registrada con el sello de tiempo y la firma que exige la ley. En una inspección, demuestras el cumplimiento en segundos."}},ctaTitle:"Empieza hoy: tu primer ticket conforme a Verifactu en menos de 5 minutos",ctaDesc:'Deja de buscar "qué es Verifactu" o preocuparte por plazos. Si buscabas un software para supermercados gratis, empieza hoy con nuestra plataforma y descubre la tranquilidad de un sistema profesional. Cumplir la normativa es tan sencillo como abrir tu TPV y empezar a vender.',ctaButton:"Comenzar",features:["TPV listo para Verifactu desde el primer día: emite tickets que cumplen la normativa sin configuraciones complejas.","Gestión de stock integrada: controla tu inventario mientras vendes, todo en una misma pantalla.","Copia de seguridad automática: tus datos de venta quedan protegidos en la nube, accesibles cuando los necesites.","Soporte humano: si tienes dudas sobre la normativa o el uso del programa, te respondemos. No bots, no bucles infinitos."]},faq:{badge:"PREGUNTAS",title:"Dudas habituales",description:"Respuestas claras a las preguntas que más se repiten.",q1:{q:"¿Puede Salut! sustituir mi TPV actual?",a:"Sí. Salut! es un ERP todo en uno que incluye un TPV moderno y rápido, funciona sin conexión y se sincroniza al instante con tu inventario."},q2:{q:"¿Tengo que comprar hardware nuevo?",a:"En la mayoría de casos, no. Salut! funciona en el navegador y es compatible con lectores de códigos de barras, impresoras de tickets y pantallas táctiles estándar. Si empiezas de cero, también ofrecemos un kit de hardware."},q3:{q:"¿Cómo funciona la predicción de inventario con IA?",a:"Pythia analiza tu historial de ventas, eventos locales e incluso patrones meteorológicos para ayudarte a pedir mejor. Detecta tendencias antes de que ocurran, reduce merma y ayuda a evitar roturas de stock."},q4:{q:"¿Cuánto se tarda en ponerlo en marcha?",a:"Podemos migrar tu tienda y dejarla operativa en solo 24 horas. Nuestro equipo se encarga de importar los datos de tu sistema anterior."},q5:{q:"¿Mis datos están seguros?",a:"Sí. Usamos cifrado de nivel empresarial para el almacenamiento y la transmisión de datos. La información de tu negocio se respalda automáticamente cada hora."}},contact:{badge:"CONTÁCTANOS",title:"Hablemos",description:"Rellena el formulario o contacta directamente por cualquiera de estas vías.",whatsapp:"WhatsApp",copied:"¡Copiado!",phone:"Teléfono",email:"Email",telegram:"Telegram",orSend:"O contáctanos directamente",nameLabel:"Nombre y apellidos",namePlaceholder:"Tu nombre",storeAddressLabel:"Dirección de la tienda",storeAddressPlaceholder:"Dirección de tu tienda",contactMethodLabel:"Método de contacto preferido",contactMethodPlaceholder:"Selecciona tu método de contacto preferido",phoneLabel:"Número de teléfono",phonePlaceholder:"Tu número de teléfono",phoneRequired:"Indica un teléfono.",telegramLabel:"Usuario de Telegram",telegramPlaceholder:"@usuario",telegramRequired:"Indica tu usuario de Telegram.",emailLabel:"Correo electrónico",emailPlaceholder:"tu@email.com",emailRequired:"Indica un correo electrónico.",msgLabel:"Mensaje",msgOptional:"(Opcional)",msgPlaceholder:"Cuéntanos brevemente qué necesitas",btnSubmit:"Enviar mensaje",submitting:"Enviando...",successTitle:"¡Formulario enviado!",submitSuccess:"Mensaje enviado. Te contactaremos pronto.",submitError:"No pudimos enviar tu mensaje. Inténtalo otra vez.",contactMethodRequired:"Selecciona tu método de contacto preferido."},cta:{heading:"¿Listo para modernizarte?",body:"Únete a más de 500 supermercados independientes que ya usan Salut!",button:"Consigue una demo gratis",trialNote:"No se requiere tarjeta • prueba gratis de 14 días"},legal:{common:{contents:"En esta página",backHome:"Volver al inicio",lastUpdatedLabel:"Última actualización",lastUpdatedValue:"9 de marzo de 2026",reviewNoticeTitle:"Contenido legal provisional",reviewNoticeBody:"Esta página es una estructura temporal preparada para revisión legal. Sustituye este texto por contenido aprobado por asesoría jurídica antes de considerarlo la política o el acuerdo definitivo."},privacy:{eyebrow:"Política de privacidad",title:"Cómo Salut gestiona la información hoy.",intro:"Esta política de privacidad provisional describe las categorías de información que esperamos recopilar y cómo esperamos utilizarlas una vez se apruebe el texto legal definitivo.",sections:{informationWeCollect:{heading:"Información que recopilamos",body:"Salut puede recopilar datos de cuenta, información de configuración de la tienda, eventos de uso, conversaciones de soporte e identificadores técnicos necesarios para operar la plataforma. Esta sección existe como reserva de estructura para el inventario de datos aprobado legalmente."},howWeUseInformation:{heading:"Cómo usamos la información",body:"Esperamos utilizar la información recopilada para prestar el servicio, mantener la seguridad de las cuentas, apoyar la implantación, mejorar el rendimiento del producto y comunicar actualizaciones importantes. El texto final debe confirmar las bases legales y los fines operativos exactos."},dataSharing:{heading:"Compartición de datos",body:"Salut puede compartir datos limitados con proveedores de infraestructura, analítica, comunicaciones o soporte que ayudan a prestar el servicio. La política final debe especificar cuándo se comparten datos, por qué se comparten y qué salvaguardas contractuales se aplican."},dataRetention:{heading:"Conservación de datos",body:"Esta versión provisional asume que los registros de cuenta y operación se conservan solo el tiempo necesario para prestar el servicio, cumplir obligaciones legales y resolver disputas. La versión final debe definir plazos concretos y flujos de eliminación."},yourRights:{heading:"Tus derechos",body:"Según la jurisdicción, los usuarios pueden tener derechos de acceso, rectificación, exportación, limitación o supresión de la información personal. Sustituye este párrafo por los derechos exactos, sus excepciones y el proceso de solicitud confirmados por el equipo legal."},contact:{heading:"Contacto",body:"Para consultas de privacidad, solicitudes de datos o reclamaciones, la política final debe dirigir a los usuarios al canal de contacto aprobado y al proceso de respuesta correspondiente. Hasta entonces, esta sección actúa solo como marcador para los datos legales y de soporte definitivos."}}},terms:{eyebrow:"Términos del servicio",title:"Las reglas para usar Salut.",intro:"Esta página provisional de términos resume las áreas contractuales principales que Salut prevé cubrir cuando los términos definitivos se revisen y aprueben.",sections:{acceptanceOfTerms:{heading:"Aceptación de los términos",body:"Al acceder o utilizar Salut, se espera que los clientes acepten los términos del servicio, las políticas aplicables y cualquier formulario de pedido o acuerdo comercial. El texto final debe definir quién contrata, cuándo se produce la aceptación y qué documentos prevalecen."},permittedUse:{heading:"Uso permitido",body:"Salut está pensado para un uso empresarial lícito vinculado a operaciones de retail. Los términos finales deben describir el uso aceptable, las actividades prohibidas y cualquier limitación específica sobre automatización, ingeniería inversa o uso indebido."},accountResponsibilities:{heading:"Responsabilidades de la cuenta",body:"Se espera que los clientes protejan sus credenciales, gestionen con cuidado los permisos de usuario y garanticen que la información enviada es correcta. Los términos aprobados también deben aclarar la responsabilidad por la actividad de los usuarios y la obligación de notificar accesos no autorizados."},serviceAvailability:{heading:"Disponibilidad del servicio",body:"Salut busca mantener el servicio disponible y fiable, pero los términos de producción deben explicar ventanas de mantenimiento, cambios planificados, gestión de incidencias y si existen compromisos de disponibilidad definidos en otro documento."},intellectualProperty:{heading:"Propiedad intelectual",body:"El acuerdo final debe confirmar que Salut conserva la titularidad sobre la plataforma, el software, la marca y la documentación, mientras que los clientes mantienen la propiedad de sus datos de negocio salvo los derechos limitados necesarios para operar el servicio."},limitationOfLiability:{heading:"Limitación de responsabilidad",body:"Este bloque reserva espacio para la distribución del riesgo comercial, incluidas las exclusiones de garantía, los topes de responsabilidad y los daños excluidos. Sustitúyelo por el texto exacto aprobado para los mercados y el modelo contractual aplicables."},contact:{heading:"Contacto",body:"Los términos finales deben identificar el contacto legal o de soporte correcto para notificaciones, disputas y consultas contractuales. Hasta su aprobación, esta sección sigue siendo únicamente un marcador estructural."}}}},blog:{sectionTitle:"Lo último del Blog",sectionSubtitle:"Ideas y estrategias para el retail alimentario moderno.",readMore:"Leer artículo",viewAll:"Ver todos los artículos"},inactivityModal:{badge:"OFERTA LIMITADA",title:"Digitaliza tu negocio hoy",description:"Únete a más de 500 negocios que ya usan Salut! para gestionar su negocio.",question:"¿Te vas sin probarlo?",subtitle:"Estás a un clic de probar el ERP más rápido del mercado.",perk1Title:"30 Días Totalmente Gratis",perk1Desc:"Sin letra pequeña. Si no te gusta, no pagas nada.",perk2:"Acceso inmediato",perk3:"Sin tarjeta de crédito requerida",btnPrimary:"Probar Salut Gratis",btnSecondary:"No, prefiero seguir gestionando mi negocio manualmente"},softwareTpvPage:{heroBadge:"Novedad: Software TPV con VeriFactu",heroTitle:"Software TPV Supermercado",heroTitleTagline:"Control Total de Tu Caja, Stock y Facturación en la Nube",heroSubtitle:"Olvídate de los programas obsoletos. Salut es el software para supermercado moderno que funciona en tu navegador: implementación en 24 horas, software para supermercados con IA integrada y tpv con verifactu listo para la normativa 2026. Todo sin instalar nada.",heroCtaPrimary:"Comenzar",heroCtaSecondary:"Ver equipos compatibles",heroTrustLine:"Sin tarjeta de crédito · Cumplimiento VeriFactu garantizado · Soporte en español",posSection:{title:"Software para TPV Rápido: Vende Más y Sin Interrupciones",item1Title:"TPV Offline: La Caja Nunca Se Detiene",item1Desc:"Si se cae Internet, sigues vendiendo. Este software para caja registradora supermercado guarda tickets localmente, controla básculas y abre el cajón. Todo se sincroniza cuando vuelva la red, sin pérdida de datos.",item2Title:"Cierre de Caja Automático en 2 Minutos",item2Desc:"Olvida contar billetes a mano. El arqueo es automático: cuadra ventas, efectivo y tarjeta sin errores ni pérdidas de tiempo. Menos trabajo administrativo y más tiempo para tus clientes."},stockSection:{title:"Inventario Inteligente: Software de Gestión para Supermercados con IA",desc:"Controla tu almacén como las grandes cadenas. Salut actualiza existencias en tiempo real, gestiona lotes y previene quiebres de stock automáticamente.",item1Title:"Caducidad y Lotes Bajo Control",item1Desc:"Alertas antes de que venzan yogures, quesos o zumos. Aplica descuentos automáticos en caja para salvar el margen en vez de tirar mercancía. La gestión de lotes que protege tu rentabilidad.",item2Title:"Pedidos a Proveedores Automatizados",item2Desc:"Nuestra IA Pythia analiza históricos de venta para calcular exactamente qué cantidad pedir. Como software ERP para supermercados, elimina estanterías vacías y exceso de stock que solo ocupa espacio.",item3Title:"Sincronización de Stock en Tiempo Real",item3Desc:"Cada venta en caja descuenta instantáneamente las unidades del almacén. Evita productos agotados sorpresa y las diferencias de inventario que tanto te cuestan."},labelsSection:{title:"Imprime Etiquetas y Tickets en el Formato Adecuado",subtitle:"Impresión rápida para todos los productos de tu tienda. Sin errores manuales ni precios desactualizados.",desc1:"Nuestro software te ayuda a imprimir etiquetas y tickets en el formato más adecuado para todos tus artículos. Al actualizar un precio o realizar una venta, Salut lo añade a la cola de impresión de inmediato.",desc2:"Compatible con cualquier impresora térmica del mercado. Códigos de barras de alta resolución que se escanean a la primera en tu TPV.",cardDesignTitle:"Vista Previa de Formato",cardPrintQueue:"Cola de Impresión",cardQueueStatus:"Imprimiendo...",labelRegular:"Precio Normal",labelPromo:"Oferta Especial",labelClearance:"Liquidación"},lawSection:{badge:"Ley Antifraude Española",titlePart1:"Prepara tu TPV para VeriFactu y",titlePart2:"evita multas de hasta 50.000€",subtitle:"A partir del 1 de enero de 2027, la AEAT exige un software de facturación certificado que envíe registros en tiempo real. Con Salut cumples la ley desde el primer día sin complicaciones.",promo:"ESPECIAL MIGRACIÓN: INSTALACIÓN 100% GRATIS",cta:"Evitar sanciones hoy",note:"Homologación VeriFactu incluida en todos nuestros planes sin costes extra"},hardwareSection:{title:"Conecta tu equipo actual o estrena un kit completo listo para vender",desc:"Salut es compatible con cualquier equipo. En caso de que no lo tengas, vendemos terminales TPV, escáneres, etc.",bullet1:"Terminales TPV Completos (Pantallas táctiles y CPU)",bullet2:"Impresoras Térmicas de Tickets",bullet3:"Lectores de Códigos de Barras y QR",bullet4:"Básculas Homologadas y Cajones Portamonedas",ctaButton:"Ver kits de equipamiento"},faq:{title:"Preguntas Frecuentes sobre Software para Supermercados",q1:{q:"¿Qué exige exactamente la AEAT al software tpv supermercado?",a:"La normativa VeriFactu obliga a que el software garantice la integridad, trazabilidad e inalterabilidad de los registros de facturación. Cada ticket debe llevar un código QR, una firma electrónica reconocida y un número de serie único. Además, el sistema debe impedir la modificación o borrado de documentos ya emitidos. Salut cumple todos estos requisitos de forma nativa, sin configuraciones complejas."},q2:{q:"¿Cómo se conecta el programa con las básculas y escáneres?",a:"Salut se integra directamente con básculas de etiquetado (Dibal, Bizerba, CAS) mediante protocolos estándar. Cuando pesas un producto, la báscula genera un código de barras con peso y precio que el TPV lee al escanear. Los escáneres funcionan por USB o Bluetooth sin drivers complicados. Es un sistema realmente plug & play."},q3:{q:"¿Cuánto tiempo lleva migrar mi base de datos de productos?",a:"Nuestro equipo de soporte realiza la importación completa de tu nomenclatura, precios, códigos de barras y proveedores en menos de 24 horas. Trabajamos con el backup de tu antiguo programa y configuramos todo antes de que abras la tienda al día siguiente. La transición es transparente: no pierdes ni una venta."},q4:{q:"¿Qué ocurre si se corta Internet en mi tienda?",a:"Salut funciona en modo offline. La caja sigue operativa, imprime tickets, abre el cajón y controla el stock localmente. Cuando la conexión vuelve, el sistema sincroniza automáticamente todas las ventas, actualizando inventarios y enviando los datos fiscales a la AEAT. Tus clientes ni se enteran del corte."}},widgets:{receipt:{title:"Impresora de Tickets Rápida",status:"IMPRIMIENDO TICKET...",itemMilk:"LECHE ENTERA 1L",itemBread:"PAN DE MOLDE",itemPasta:"PASTA GALLO",subtotal:"SUBTOTAL",tax:"IVA (10%)",total:"TOTAL",compliant:"CONFORME A VERIFACTU"},expiration:{title:"Alertas de Caducidad",yogurt:"Yogur Desnatado",cheese:"Queso Tierno",juice:"Zumo de Naranja"},seal:{pathText:"• SISTEMA CERTIFICADO AEAT • VERIFACTU 2026",certified:"CERTIFICADO"}}},footer:{slogan:"El ERP para supermercados impulsado por IA y diseñado para crecer.",product:"Producto",legal:"Legal",blog:"Blog",privacy:"Política de Privacidad",terms:"Términos de Servicio",rights:"© {year} Salut! Systems. Todos los derechos reservados."},impresoraTicketsPage:{heroBadge:"Impresora TPV",heroTitle:"Impresora de Tickets y Etiquetas para Supermercados",heroTitleTagline:"Impresión Térmica de Alta Velocidad y Diseño Automático de Etiquetas",heroSubtitle:"Integración completa con tu caja registradora. Imprime recibos de clientes al instante y automatiza la generación de etiquetas de precios para todos tus artículos.",heroCtaPrimary:"Comenzar ahora",heroCtaSecondary:"Ver beneficios del ERP",heroTrustLine:"Totalmente compatible con cualquier impresora tpv térmica · Conforme a VeriFactu · Configuración Plug & Play",automationBadge:"Automatización de Precios",automationTitle:"Impresión Automática de Etiquetas",automationSubtitle:"Olvídate de crear las etiquetas a mano. En el momento en que registras o actualizas un producto en el ERP de Salut, su etiqueta con código de barras y precio se genera automáticamente.",automationDesc1:"Nuestra sistema automáticamente imprimirá o preparará para imprimir las etiquetas de precios para todos los productos que ingreses en el sistema ERP. Olvídate de crearlas a mano una por una y ahorra horas de trabajo.",automationDesc2:"Ya sea que utilices precios regulares, precios promocionales o descuentos por liquidación, los diseños de Salut se adaptan de forma automática con códigos de barras de alta resolución y tasas de IVA correctas.",statBadge:"Impacto en Ventas",statTitle:"Incrementa tus Ventas Diarias un 20% - 30%",statDesc1:"Nuestros datos demuestran que disponer de etiquetas de precios claras, legibles y actualizadas en los estantes influye de forma directa en la decisión de compra de tus clientes.",statDesc2:"Este beneficio es especialmente notable en la sección de alcohol y bebidas espirituosas, donde la colocación de etiquetas de precios incrementa las ventas diarias de dichos productos entre un 20% y un 30%. No pierdas ventas por falta de claridad.",hardwareBadge:"Compatibilidad de Hardware",hardwareTitle:"Compatible con cualquier impresora tpv térmica",hardwareDesc:"Salut se conecta sin problemas con tus dispositivos actuales. Si ya tienes una impresora de tickets en tu punto de venta, funcionará desde el primer día sin necesidad de controladores complejos.",hardwareBullet1:"Impresoras térmicas estándar de 80 mm y 58 mm",hardwareBullet2:"Soporte completo para marcas líderes como Epson, Star Micronics, Zebra y Bixolon",hardwareBullet3:"Conexión flexible mediante USB, Ethernet (LAN), Wi-Fi o Bluetooth",hardwareBullet4:"Tickets conformes a VeriFactu con códigos QR y firmas electrónicas integradas"},comparativasPage:{heroBadge:"Comparativas",heroTitle:"El mejor programa verifactu supermercado: Salut vs el resto",heroSubtitle:"Por qué los supermercados independientes están migrando de sistemas anticuados y ERPs genéricos a la inteligencia artificial de Salut.",traditionalTitle:"Salut vs Software Tradicional y Legacy",traditionalDesc:"Programas clásicos como Gesvent (incluyendo Gesvent 8), Verial (y su módulo Verial Supermercados) o TPV GLOP han sido el estándar durante años. Opciones como gotpv, jpc informatica o SolverMedia suelen requerir instalaciones locales o servidores costosos.",traditionalAdvantage:"Ventaja Salut: 100% en la nube, actualizaciones automáticas, sin servidores locales y predicción de demanda mediante IA.",genericTitle:"Salut vs ERPs Genéricos de Contabilidad",genericDesc:"Buscar odoo verifactu, factusol verifactu o holded verifactu es común para cumplir la ley, pero son ERPs genéricos que requieren costosas adaptaciones.",genericAdvantage:"Ventaja Salut: A diferencia de Holded u Odoo, Salut está creado exclusivamente para supermercados. TPV ultrarrápido y control de estantería nativo.",tableTitle:"Tabla Comparativa Definitiva",tableCols:{salut:"Salut ERP",traditional:"Tradicional Software",generic:"Genérico ERP"},tableRows:{ai:"Predicción de demanda con IA",focus:"100% especializado en supermercados",cloud:"Sin servidores locales (Cloud)",ui:"Interfaz moderna e intuitiva"},btnSoftwareTpv:"Leer más sobre Salut",verifactuTitle:"La importancia de cumplir con VeriFactu",verifactuDesc:"Salut garantiza que tu TPV cumple con la Agencia Tributaria desde el primer minuto. Es el programa verifactu supermercado más fácil de implementar, sin costes ocultos.",btnVerifactu:"Saber más sobre VeriFactu",migrationTitle:"Migración sin fricciones",migrationDesc:"¿Es difícil migrar mis datos desde Gesvent 8 o Verial Supermercados a Salut? Para nada. Nos encargamos de todo el proceso de importación.",btnMigration:"Ver cómo funciona",ctaTitle:"No te quedes en el pasado con sistemas que limitan tu crecimiento.",ctaButton:"Empieza hoy con Salut"}}};function t(e,a){let t=a.split("."),o=e;for(let e of t){if("object"!=typeof o||null===o)return;let a=o[e];if(void 0===a)return;o=a}return o}e.s(["createTranslator",0,function(e){return o=>{let r;return"string"==typeof(r=t(a[e],o))?r:o}},"getTranslationArray",0,function(e,o){let r=t(a[e],o);return Array.isArray(r)?r:[]}])}]);